app.config["MAIL_USERNAME"] = os.environ.get("MAIL_USERNAME")
app.config["MAIL_PASSWORD"] = os.environ.get("MAIL_PASSWORD")
mail = Mail(app)

@app.route("/reset-mfa", methods=["POST"])
def reset_mfa():
    email = request.json["email"]
    user = User.query.filter_by(email=email).first()
    if not user:
        return jsonify({"error": "User not found"}), 404
    token = hashlib.sha256(os.urandom(128)).hexdigest()
    user.mfa_token = token
    user.save()
    msg = Message("Reset MFA", sender="noreply@example.com", recipients=[email])
    msg.body = f"To reset your MFA settings, click on the following link: {app.config['MAIL_SERVER']}/reset-mfa?token={token}"
    mail.send(msg)
