@app.route("/reset-mfa", methods=["GET"])
def reset_mfa():
    token = request.args.get("token")
    user = User.query.filter_by(mfa_token=token).first()
    if not user:
        return jsonify({"error": "Invalid token"}), 403
    user.mfa_token = None
    user.save()
    return jsonify({"message": "MFA reset successfully"}), 200